import { Component, inject, signal, OnInit } from '@angular/core';
import { Router, ActivatedRoute } from '@angular/router';
import { UserSessionService } from '../../../../core/services/user-session.service';
import { ClientSelectorComponent } from '../../../../shared/components/client-selector/client-selector.component';
import { CommonModule } from '@angular/common';
import { ButtonModule } from 'primeng/button';
import { AuthService as ApiAuthService } from '../../../../api';
import { AuthTokenManagerService } from '../../../../core/services/auth-token-manager.service';
import { firstValueFrom } from 'rxjs';

@Component({
  selector: 'app-select-client',
  templateUrl: './select-client.component.html',
  styleUrls: ['./select-client.component.scss'],
  standalone: true,
  imports: [ClientSelectorComponent, CommonModule, ButtonModule],
})
export class SelectClientComponent implements OnInit {
  private readonly userSessionService = inject(UserSessionService);
  private readonly router = inject(Router);
  private readonly route = inject(ActivatedRoute);
  private readonly apiAuthService = inject(ApiAuthService);
  private readonly authTokenManager = inject(AuthTokenManagerService);

  accounts = this.userSessionService.userSessions();
  loading = signal(false);
  isPasswordResetMode = false;

  ngOnInit(): void {
    // Check if we're in password reset mode
    const resetPassword = this.route.snapshot.queryParams['resetPassword'];
    this.isPasswordResetMode = resetPassword === 'true';
  }

  async onAccountSelected(accountId: string): Promise<boolean> {
    this.loading.set(true);

    try {
      // In password reset mode, we don't need to call selectUser API
      // because we're already authenticated via the token
      if (this.isPasswordResetMode) {
        this.userSessionService.setCurrentUserSession(accountId);
        this.loading.set(false);
        return this.router.navigate(['/auth', 'reset-password-welcome']);
      }

      // Normal flow: select user and navigate to app
      const response = await firstValueFrom(
        this.apiAuthService.selectUser(accountId),
      );

      this.authTokenManager.storeTokens({
        accessToken: response.accessToken,
        refreshToken: response.refreshToken,
        idToken: response.idToken ?? '',
        users: this.accounts, // Keep existing user sessions
      });

      this.userSessionService.setCurrentUserSession(accountId);

      this.loading.set(false);
      return this.router.navigate(['/position']);
    } catch (error) {
      console.error('Error selecting user:', error);
      this.loading.set(false);
      // Stay on selection page if error occurs
      return false;
    }
  }

  cancel(): Promise<boolean> {
    this.userSessionService.clearAllSessions();
    return this.router.navigate(['/auth/login']);
  }
}
